import{_ as a,o as i,c as e,e as t}from"./app.2ab19930.js";const r={},n=t('<h1 id="\u6982\u7387\u8BBA\u4E0E\u6570\u7406\u7EDF\u8BA1" tabindex="-1"><a class="header-anchor" href="#\u6982\u7387\u8BBA\u4E0E\u6570\u7406\u7EDF\u8BA1" aria-hidden="true">#</a> \u6982\u7387\u8BBA\u4E0E\u6570\u7406\u7EDF\u8BA1</h1><p>\u6837\u672C\u8DDF\u6837\u672C\u7A7A\u95F4\u5728\u67D0\u4E2A\u7EF4\u5EA6\u53D1\u751F\u7684\u4E00\u79CD\u5173\u7CFB\u5373\u4E3A\u6982\u7387\u3002</p><h2 id="\u4E00\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u6982\u7387\u5206\u5E03\u5185\u5BB9\u601D\u7EF4\u5BFC\u56FE" tabindex="-1"><a class="header-anchor" href="#\u4E00\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u6982\u7387\u5206\u5E03\u5185\u5BB9\u601D\u7EF4\u5BFC\u56FE" aria-hidden="true">#</a> \u4E00\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u6982\u7387\u5206\u5E03\u5185\u5BB9\u601D\u7EF4\u5BFC\u56FE</h2><div style="text-align:center;"><img alt="2.4\u601D\u7EF4\u5BFC\u56FE" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_1.jpg" width="100%" height="100%"></div><h2 id="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u5176\u5206\u5E03\u6982\u5FF5\u8FA8\u6790" tabindex="-1"><a class="header-anchor" href="#\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u5176\u5206\u5E03\u6982\u5FF5\u8FA8\u6790" aria-hidden="true">#</a> \u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u5176\u5206\u5E03\u6982\u5FF5\u8FA8\u6790</h2><div style="text-align:center;"><img alt="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u5176\u5206\u5E03\u6982\u5FF5\u8FA8\u6790" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_2.jpg" width="100%" height="100%"></div><div style="text-align:center;"><img alt="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u53CA\u5176\u5206\u5E03\u6982\u5FF5\u8FA8\u6790" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_3.jpg" width="100%" height="100%"></div><h2 id="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u7684\u6761\u4EF6\u5206\u5E03" tabindex="-1"><a class="header-anchor" href="#\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u7684\u6761\u4EF6\u5206\u5E03" aria-hidden="true">#</a> \u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u7684\u6761\u4EF6\u5206\u5E03</h2><div style="text-align:center;"><img alt="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u7684\u6761\u4EF6\u5206\u5E03" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_4.jpg" width="100%" height="100%"></div><div style="text-align:center;"><img alt="\u4E8C\u7EF4\u968F\u673A\u53D8\u91CF\u7684\u6761\u4EF6\u5206\u5E03" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_5.jpg" width="100%" height="100%"></div><h2 id="\u9898\u578B-\u82E5x\u662F\u8FDE\u7EED\u578B\u968F\u673A\u53D8\u91CF-\u5DF2\u77E5x\u7684\u5206\u5E03\u51FD\u6570-\u5982\u4F55\u6C42y-g-x-\u7684\u5206\u5E03\u51FD\u6570" tabindex="-1"><a class="header-anchor" href="#\u9898\u578B-\u82E5x\u662F\u8FDE\u7EED\u578B\u968F\u673A\u53D8\u91CF-\u5DF2\u77E5x\u7684\u5206\u5E03\u51FD\u6570-\u5982\u4F55\u6C42y-g-x-\u7684\u5206\u5E03\u51FD\u6570" aria-hidden="true">#</a> \u9898\u578B\uFF1A\u82E5X\u662F<em><strong>\u8FDE\u7EED\u578B</strong></em>\u968F\u673A\u53D8\u91CF\uFF0C\u5DF2\u77E5X\u7684\u5206\u5E03\u51FD\u6570\uFF0C\u5982\u4F55\u6C42Y=g\uFF08X\uFF09\u7684\u5206\u5E03\u51FD\u6570\uFF1F</h2><h3 id="\u6CD5\u4E00-\u5206\u5E03\u51FD\u6570\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u6CD5\u4E00-\u5206\u5E03\u51FD\u6570\u6CD5" aria-hidden="true">#</a> \u6CD5\u4E00\uFF1A\u5206\u5E03\u51FD\u6570\u6CD5</h3><div style="text-align:center;"><img alt="\u5206\u5E03\u51FD\u6570\u6CD5" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_6.jpg" width="100%" height="100%"></div><h3 id="\u6CD5\u4E8C-\u516C\u5F0F\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u6CD5\u4E8C-\u516C\u5F0F\u6CD5" aria-hidden="true">#</a> \u6CD5\u4E8C\uFF1A\u516C\u5F0F\u6CD5</h3><div style="text-align:center;"><img alt="\u516C\u5F0F\u6CD5" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_7.jpg" width="100%" height="100%"></div><h2 id="\u3010\u96BE\u70B9\u3011\u4E24\u4E2A\u968F\u673A\u53D8\u91CF\u51FD\u6570\u7684\u5206\u5E03" tabindex="-1"><a class="header-anchor" href="#\u3010\u96BE\u70B9\u3011\u4E24\u4E2A\u968F\u673A\u53D8\u91CF\u51FD\u6570\u7684\u5206\u5E03" aria-hidden="true">#</a> \u3010\u96BE\u70B9\u3011\u4E24\u4E2A\u968F\u673A\u53D8\u91CF\u51FD\u6570\u7684\u5206\u5E03</h2><div style="text-align:center;"><img alt="\u4E24\u4E2A\u968F\u673A\u53D8\u91CF\u51FD\u6570\u7684\u5206\u5E03" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_8.jpg" width="100%" height="100%"></div><div style="text-align:center;"><img alt="\u4E24\u4E2A\u968F\u673A\u53D8\u91CF\u51FD\u6570\u7684\u5206\u5E03" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_9.jpg" width="100%" height="100%"></div><h2 id="\u3010\u603B\u7ED3\u3011\u5E38\u89C1\u5206\u5E03\u7684\u671F\u671B\u4E0E\u65B9\u5DEE" tabindex="-1"><a class="header-anchor" href="#\u3010\u603B\u7ED3\u3011\u5E38\u89C1\u5206\u5E03\u7684\u671F\u671B\u4E0E\u65B9\u5DEE" aria-hidden="true">#</a> \u3010\u603B\u7ED3\u3011\u5E38\u89C1\u5206\u5E03\u7684\u671F\u671B\u4E0E\u65B9\u5DEE</h2><div style="text-align:center;"><img alt="\u5E38\u89C1\u5206\u5E03\u7684\u671F\u671B\u4E0E\u65B9\u5DEE" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/probability_10.jpg" width="100%" height="100%"></div><h2 id="\u3010\u96BE\u70B9\u3011\u5927\u6570\u5B9A\u5F8B\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u3010\u96BE\u70B9\u3011\u5927\u6570\u5B9A\u5F8B\u603B\u7ED3" aria-hidden="true">#</a> \u3010\u96BE\u70B9\u3011\u5927\u6570\u5B9A\u5F8B\u603B\u7ED3</h2><h3 id="\u5207\u6BD4\u96EA\u592B\u4E0D\u7B49\u5F0F" tabindex="-1"><a class="header-anchor" href="#\u5207\u6BD4\u96EA\u592B\u4E0D\u7B49\u5F0F" aria-hidden="true">#</a> \u5207\u6BD4\u96EA\u592B\u4E0D\u7B49\u5F0F</h3><p><strong>\u5B9A\u7406</strong>\uFF1A$X$\u4E3A\u968F\u673A\u53D8\u91CF\uFF0C\u82E5$EX,DX$\u5B58\u5728\uFF0C\u5219\u5BF9\u4E8E$\\forall \\varepsilon &gt;0$,</p><p>$$P{|X-E(X)|\\ge \\varepsilon}\\le \\frac{D(X)}{\\varepsilon^2}$$ \u6216 $$P{|X-E(X)|&lt; \\varepsilon}\\ge 1-\\frac{D(X)}{\\varepsilon^2}$$</p><p><strong>\u8BC1\u660E</strong>\uFF1A\u8BBE$X$\u662F\u8FDE\u7EED\u578B\u968F\u673A\u53D8\u91CF\uFF0C\u5DE6\u8FB9= $$\\int_{|X-E(X)|\\ge \\varepsilon}f(x)dx\\le \\int_{|X-E(X)|\\ge \\varepsilon}\\frac{(X-E(X))^2}{\\varepsilon ^2}f(x)dx$$</p><p>$\\because \\frac{(X-E(X))^2}{\\varepsilon ^2}f(x)&gt;0$\uFF0C\u6545\uFF1A</p><p>$$\\int_{|X-E(X)|\\ge \\varepsilon}\\frac{(X-E(X))^2}{\\varepsilon ^2}f(x)dx\\le \\int_{-\\infty}^{\\infty}\\frac{(X-E(X))^2}{\\varepsilon ^2}f(x)dx$$</p><p>$$=\\frac{1}{\\varepsilon^2}\\int_{-\\infty}^{\\infty}(|X-E(X)|)^2 f(x)dx=\\frac{E(|X-E(X)|)^2}{\\varepsilon ^2}=\\frac{D(X)}{\\varepsilon ^2}$$</p><p>\u7EFC\u4E0A\u6240\u8FF0\uFF1A $$P{|X-E(X)|\\ge \\varepsilon}\\le \\frac{D(X)}{\\varepsilon^2}$$ \u5F97\u8BC1\uFF01</p><h3 id="\u4F9D\u6982\u7387\u6536\u655B\u5B9A\u4E49\u5F15\u5165" tabindex="-1"><a class="header-anchor" href="#\u4F9D\u6982\u7387\u6536\u655B\u5B9A\u4E49\u5F15\u5165" aria-hidden="true">#</a> \u4F9D\u6982\u7387\u6536\u655B\u5B9A\u4E49\u5F15\u5165</h3><p>\u56DE\u987E\u6536\u655B\u5B9A\u4E49\uFF1A$a_n\\to a$</p><p>$$\\forall \\varepsilon &gt;0, \\exists N&gt;0, \u4F7F\u5F97n&gt;N\u65F6\uFF0C|a_n-a|&lt;\\varepsilon$$</p><p>\u4F9D\u6982\u7387\u6536\u655B\uFF1A$a_n \\overset{P}{\\rightarrow} a$ $$\\forall \\varepsilon &gt;0, \\exists N&gt;0, \u4F7F\u5F97n&gt;N\u65F6\uFF0CP{|a_n-a|&lt;\\varepsilon}=1$$ (\u7406\u89E3\uFF1A\u6982\u7387\u65E0\u9650\u903C\u8FD1\u4F46\u4E0D\u7B49\u4E8E1\uFF0C\u4E0D\u4EE3\u8868\u4E00\u5B9A\u6EE1\u8DB3$|a_n-a|&lt;\\varepsilon$\uFF0C\u53EF\u80FD\u5076\u5C14\u6709\u4E00\u4E24\u4E2A\u70B9\u5B58\u5728\u7279\u6B8A\u60C5\u51B5)</p><p>\u5982\uFF1A\u9891\u7387$\\overset{P}{\\rightarrow}$\u6982\u7387\uFF0C\u4EE3\u8868\u65E0\u6570\u6B21\u5B9E\u9A8C\u540E\uFF0C\u9891\u7387\u4F9D\u6982\u7387\u6536\u655B\u4E8E\u5176\u6982\u7387\uFF0C\u4F46\u662F\u603B\u6709\u8FD9\u4E48\u4E00\u4E24\u6B21\u5B9E\u9A8C\uFF0C\u9891\u7387\u548C\u6982\u7387\u5DEE\u7684\u5F88\u8FDC\uFF08\u5373\uFF1A\u5B9E\u9A8C\u5076\u7136\u6027\uFF09</p><h3 id="\u4F2F\u52AA\u5229\u5927\u6570\u5B9A\u5F8B" tabindex="-1"><a class="header-anchor" href="#\u4F2F\u52AA\u5229\u5927\u6570\u5B9A\u5F8B" aria-hidden="true">#</a> \u4F2F\u52AA\u5229\u5927\u6570\u5B9A\u5F8B</h3><p><strong>\u5B9A\u7406</strong>\uFF1A\u5BF9\u4E8E$n$\u91CD\u4F2F\u52AA\u5229\u8BD5\u9A8C\uFF0C$A$\u53D1\u751F\u4E86$m_n$\u6B21\uFF0C\u5219\u9891\u7387\u4E3A$\\frac{m_n}{n}$\uFF0C\u8BBE\u6982\u7387\u4E3A$p$\uFF0C\u5BF9$\\forall \\varepsilon &gt;0$\uFF0C\u5219\u6709\uFF1A $$\\lim_{n \\to \\infty} P{|\\frac{m_n}{n}-p|&lt;\\varepsilon}=1$$</p><p><strong>\u8BC1\u660E</strong>\uFF1A\u8BBE$m_n\\sim B(n,p)$\uFF0C\u5219$E(X)=np,D(X)=np(1-p)$\uFF0C\u6545\uFF0C$E(\\frac{m_n}{n})=p,D(\\frac{m_n}{n})=\\frac{p(1-p)}{n}$\uFF0C\u7531<strong>\u5207\u6BD4\u96EA\u592B\u4E0D\u7B49\u5F0F</strong>\uFF0C $$1\\ge P{|\\frac{m_n}{n}-E(\\frac{m_n}{n})|&lt; \\varepsilon}\\ge 1-\\frac{D(X)}{\\varepsilon^2}$$ \u5C06$E(\\frac{m_n}{n})=p,D(\\frac{m_n}{n})=\\frac{p(1-p)}{n}$\u4EE3\u5165\u53EF\u5F97\uFF1A $$1\\ge P{|\\frac{m_n}{n}-p|&lt; \\varepsilon}\\ge 1-\\frac{p(1-p)}{n\\varepsilon^2}$$ \u5F53$n\\to \\infty$\u65F6\uFF0C $$\\lim_{n \\to \\infty} 1=1,\\lim_{n \\to \\infty}1-\\frac{p(1-p)}{n\\varepsilon^2}=1$$</p><p>\u6545\u7531\u5939\u903C\u5B9A\u7406\uFF0C</p><p>$$\\lim_{n \\to \\infty} P{|\\frac{m_n}{n}-p|&lt;\\varepsilon}=1$$</p><h3 id="\u5207\u6BD4\u96EA\u592B\u5927\u6570\u5B9A\u5F8B" tabindex="-1"><a class="header-anchor" href="#\u5207\u6BD4\u96EA\u592B\u5927\u6570\u5B9A\u5F8B" aria-hidden="true">#</a> \u5207\u6BD4\u96EA\u592B\u5927\u6570\u5B9A\u5F8B</h3><p><strong>\u5B9A\u7406</strong>\uFF1A\u82E5$X_1,X_2,X_3,\\cdots ,X_n$\u662F<strong>\u4E24\u4E24\u4E0D\u76F8\u5173</strong>\u7684\u53D8\u91CF\uFF08\u6CA1\u8BF4\u540C\u5206\u5E03\uFF0C\u4E5F\u6CA1\u8BF4\u72EC\u7ACB\uFF09\uFF0C\u82E5$E(X_i)\uFF0CD(X_i)$\u5747\u5B58\u5728\u4E14\u65B9\u5DEE\u6709\u754C\uFF08$D(X_i)\\le M$\uFF09,\u5219\u5BF9\u4E8E$\\forall \\varepsilon &gt;0$\uFF0C</p><p>$$\\lim_{n \\to \\infty}P{|\\frac{1}{n}\\sum_{i=1}^{n}X_i-\\frac{1}{n}\\sum_{i=1}^{n}E(X_i)|&lt;\\varepsilon}=1$$</p><p>\u5373\uFF1A\u65E0\u6570\u6B21\u5B9E\u9A8C\u540E\uFF0C\u53D8\u91CF\u7684\u5747\u503C\u4F1A\u4F9D\u6982\u7387\u6536\u655B\u4E8E\u671F\u671B\u7684\u5747\u503C</p><p><strong>\u8BC1\u660E</strong>\uFF1A $$E(\\frac{1}{n}\\sum_{i=1}^{n}X_i)=\\frac{1}{n}\\sum_{i=1}^{n}E(X_i)$$</p><p>\u7531\u4E8E$X_1,X_2,X_3,\\cdots ,X_n$\u662F<strong>\u4E24\u4E24\u4E0D\u76F8\u5173</strong>\u7684\u53D8\u91CF\uFF0C\u6545\uFF1A</p><p>$$D(\\frac{1}{n}\\sum_{i=1}^{n}X_i)=\\frac{1}{n^2}\\sum_{i=1}^{n}D(X_i)$$</p><p>\u7531<strong>\u5207\u6BD4\u96EA\u592B\u4E0D\u7B49\u5F0F</strong>\uFF1A</p><p>$$1\\ge P{|\\frac{1}{n}\\sum_{i=1}^{n}X_i-\\frac{1}{n}\\sum_{i=1}^{n}E(X_i)|&lt;\\varepsilon}\\ge 1-\\frac{1}{n^2\\varepsilon^2}\\sum_{i=1}^{n}D(X_i)$$</p><p>\u800C\u5F53$n \\to \\infty$\u65F6\uFF0C</p><p>$$\\lim_{n \\to \\infty} 1=1,\\lim_{n \\to \\infty}1-\\frac{1}{n^2\\varepsilon^2}\\sum_{i=1}^{n}D(X_i)=1$$</p><p>\u6545\u7531\u5939\u903C\u5B9A\u7406\uFF1A</p><p>$$\\lim_{n \\to \\infty}P{|\\frac{1}{n}\\sum_{i=1}^{n}X_i-\\frac{1}{n}\\sum_{i=1}^{n}E(X_i)|&lt;\\varepsilon}=1$$</p><ul><li>\u63A8\u8BBA\uFF1A</li></ul><p>\u82E5$X_1,X_2,X_3,\\cdots ,X_n$\u76F8\u4E92\u72EC\u7ACB\u4E14\u540C\u5206\u5E03\uFF0C$E(X_i)=\\mu ,D(X_i)=\\sigma^2$,\u5219\u5BF9\u4E8E$\\forall \\varepsilon &gt;0$,</p><p>$$\\lim_{n \\to \\infty}P{|\\frac{1}{n}\\sum_{i=1}^{n}X_i-\\mu|&lt;\\varepsilon}=1$$</p><h3 id="\u8F9B\u94A6\u5927\u6570\u5B9A\u5F8B" tabindex="-1"><a class="header-anchor" href="#\u8F9B\u94A6\u5927\u6570\u5B9A\u5F8B" aria-hidden="true">#</a> \u8F9B\u94A6\u5927\u6570\u5B9A\u5F8B</h3><p>\u82E5$X_1,X_2,X_3,\\cdots ,X_n$\u76F8\u4E92\u72EC\u7ACB\u4E14\u540C\u5206\u5E03\uFF0C$E(X_i)=\\mu$ ,<strong>\u65B9\u5DEE\u65E0\u8981\u6C42</strong>,\u5219\u5BF9\u4E8E$\\forall \\varepsilon &gt;0$,</p><p>$$\\lim_{n \\to \\infty}P{|\\frac{1}{n}\\sum_{i=1}^{n}X_i-\\mu|&lt;\\varepsilon}=1$$</p><h2 id="\u76F8\u5173\u7CFB\u6570-rho-xy-le-1-\u7684\u8BC1\u660E" tabindex="-1"><a class="header-anchor" href="#\u76F8\u5173\u7CFB\u6570-rho-xy-le-1-\u7684\u8BC1\u660E" aria-hidden="true">#</a> \u76F8\u5173\u7CFB\u6570$|\\rho_{XY}|\\le 1$\u7684\u8BC1\u660E</h2><p><strong>\u8BC1\u660E\u5982\u4E0B\uFF1A</strong></p><p>\u6784\u9020</p><p>$$ \\begin{align} e(a,b)&amp;=E{[Y-(a+bx)]^2}\\ \\ &amp;=E(Y^2)+b^2E(X^2)+a^2-2bE(XY)+2abE(X)-2aE(Y) \\end{align}$$</p><p>$e$\u53EF\u770B\u4F5C$a,b$\u7684\u51FD\u6570\uFF0C\u6545\u7531\u591A\u5143\u51FD\u6570\u6C42\u6781\u503C\u7684\u65B9\u6CD5\uFF0C\u53EF\u5F97\uFF1A $$ \\begin{cases} \\frac{\\partial e}{\\partial a}=2a+2bE(X)-2E(Y)=0\\ \\ \\frac{\\partial e}{\\partial b}=2bE(X^2)-2E(XY)+2aE(X)=0 \\end{cases} $$</p><p>\u89E3\u5F97\uFF1A $$ \\begin{gather} b_0=\\frac{Cov(X,Y)}{D(X)}\\ \\ a_0=E(X)\\left[1-\\frac{Cov(X,Y)}{D(X)}\\right] \\end{gather} $$</p><p>\u4E14\u7531\u7B2C\u4E00\u5F0F\u53EF\u5F97\uFF1A</p><p>$$E(Y-bx-a)=0$$</p><p>\u6545\uFF1A</p><p>$$ \\begin{align} e(a_0,b_0)&amp;=E{[Y-(a_0+b_0x)]^2}\\ \\ &amp;=D[Y-(a_0+b_0x)]+E^2[Y-(a_0+b_0x)]\\ \\ \u7531E(Y-bx-a)=0\uFF0C\u5F97\u5230\uFF1A\\ \\ e(a_0,b_0)&amp;=D[Y-(a_0+b_0x)]\\ \\ &amp;=D(Y)-b_0^2D(X)+2b_0Cov(X,Y)\\ \\ &amp;=D(Y)-\\frac{Cov^2(X,Y)}{D(X)}+2\\frac{Cov^2(X,Y)}{D(X)}\\ \\ &amp;=D(Y)-\\frac{Cov^2(X,Y)}{D(X)}\\ \\ &amp;=D(Y)\\left[1-\\frac{Cov^2(X,Y)}{D(X)D(Y)}\\right]\\ \\ &amp;=D(Y)(1-\\rho_{XY}^2) \\end{align} $$</p><p>\u800C\u7531\u4E8E$[Y-(a_0+b_0x)]^2\\ge 0$\uFF0C\u6545$e(a_0,b_0)\\ge 0$\uFF0C\u6545$1-\\rho_{XY}^2\\ge 0$\uFF0C\u5373\uFF1A</p><p>$$\\rho_{XY}^2\\le 1$$</p>',70),p=[n];function h(s,o){return i(),e("div",null,p)}var $=a(r,[["render",h],["__file","probability.html.vue"]]);export{$ as default};
